from RestrictedPython import compile_restricted, safe_globals
from RestrictedPython.Guards import safe_builtins, guarded_iter_unpack_sequence

def run_restricted(code: str, extra_globals: dict | None = None) -> dict:
    """Run code with AST-level restrictions. Must still run inside a container."""
    try:
        compiled = compile_restricted(code, '<agent>', 'exec')
    except SyntaxError as e:
        return {"error": f"SyntaxError: {e}"}

    glb = {
        **safe_globals,
        '__builtins__': safe_builtins,
        '_getiter_': iter,
        '_iter_unpack_sequence_': guarded_iter_unpack_sequence,
    }
    if extra_globals:
        glb.update(extra_globals)

    loc: dict = {}
    try:
        exec(compiled, glb, loc)  # noqa: S102
        return {"locals": {k: v for k, v in loc.items() if not k.startswith('_')}}
    except Exception as e:
        return {"error": str(e)}

# Example: agent code that is safe
result = run_restricted("""
data = [1, 2, 3, 4, 5]
total = sum(data)
mean = total / len(data)
""")
print(result)  # {'locals': {'data': [...], 'total': 15, 'mean': 3.0}}
